const SPR_ANIM  = id => `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/versions/generation-v/black-white/animated/${id}.gif`;
const SD_ANI    = n  => `https://play.pokemonshowdown.com/sprites/ani/${n}.gif`;
const SD_HOME   = n  => `https://play.pokemonshowdown.com/sprites/home/${n}.png`;

// تحويل اسم البوكيمون إلى Showdown slug تلقائياً
function nameToSD(name){
  return name.toLowerCase()
    .replace(/♀/g,'-f').replace(/♂/g,'-m')
    .replace(/[éèê]/g,'e').replace(/['\u2019.]/g,'')
    .replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,'');
}

